package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Field;
import java.util.Iterator;
import java.util.NoSuchElementException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVParserTest {

    private CSVParser csvParser;

    @BeforeEach
    void setUp() throws Exception {
        csvParser = Mockito.spy(new CSVParser(null, null));

        // Use reflection to override private nextRecord() method behavior
        // Because CSVParser is final and nextRecord() is package-private, we mock it via Mockito
        doAnswer(invocation -> {
            Field countField;
            try {
                countField = CSVParserTest.class.getDeclaredField("count");
            } catch (NoSuchFieldException e) {
                countField = null;
            }
            if (countField == null) {
                // Initialize count field in spy instance
                Field f = csvParser.getClass().getDeclaredField("count");
                f.setAccessible(true);
                f.set(csvParser, 0);
            }
            Field f = csvParser.getClass().getDeclaredField("count");
            f.setAccessible(true);
            int count = (int) (f.get(csvParser) == null ? 0 : f.get(csvParser));
            if (count == 0) {
                f.set(csvParser, 1);
                return createCSVRecord(0, 0);
            } else if (count == 1) {
                f.set(csvParser, 2);
                return createCSVRecord(1, 1);
            } else {
                return null;
            }
        }).when(csvParser).nextRecord();

        // Add count field dynamically to spy instance
        try {
            Field countField = csvParser.getClass().getDeclaredField("count");
        } catch (NoSuchFieldException e) {
            // Add count field dynamically is not possible, use a wrapper class instead
        }
    }

    private CSVRecord createCSVRecord(int recordNumber, int position) throws Exception {
        // CSVRecord constructor is package-private and requires parameters:
        // CSVParser parser, Map<String, Integer> headerMap, long recordNumber, long characterPosition
        // We'll pass null for headerMap and parser, as in original test.
        return new CSVRecord(csvParser, null, recordNumber, position);
    }

    @Test
    void testIteratorHasNextAndNext() {
        Iterator<CSVRecord> iterator = csvParser.iterator();

        // First record
        assertTrue(iterator.hasNext());
        CSVRecord record1 = iterator.next();
        assertNotNull(record1);

        // Second record
        assertTrue(iterator.hasNext());
        CSVRecord record2 = iterator.next();
        assertNotNull(record2);
        assertNotSame(record1, record2);

        // No more records
        assertFalse(iterator.hasNext());
        assertThrows(NoSuchElementException.class, iterator::next);
    }

    @Test
    void testIteratorNextWithoutHasNext() {
        Iterator<CSVRecord> iterator = csvParser.iterator();

        // Call next without hasNext()
        CSVRecord record1 = iterator.next();
        assertNotNull(record1);

        CSVRecord record2 = iterator.next();
        assertNotNull(record2);

        assertThrows(NoSuchElementException.class, iterator::next);
    }

    @Test
    void testIteratorRemoveThrows() {
        Iterator<CSVRecord> iterator = csvParser.iterator();
        assertThrows(UnsupportedOperationException.class, iterator::remove);
    }

    @Test
    void testIteratorHasNextWhenClosed() {
        CSVParser closedParser = Mockito.spy(csvParser);
        doReturn(true).when(closedParser).isClosed();
        Iterator<CSVRecord> iterator = closedParser.iterator();
        assertFalse(iterator.hasNext());
        assertThrows(NoSuchElementException.class, iterator::next);
    }

    @Test
    void testIteratorNextThrowsRuntimeExceptionOnIOException() throws IOException {
        CSVParser errorParser = Mockito.spy(csvParser);
        doThrow(new IOException("IO error")).when(errorParser).nextRecord();
        Iterator<CSVRecord> iterator = errorParser.iterator();

        RuntimeException ex = assertThrows(RuntimeException.class, iterator::hasNext);
        assertTrue(ex.getCause() instanceof IOException);

        RuntimeException exNext = assertThrows(RuntimeException.class, iterator::next);
        assertTrue(exNext.getCause() instanceof IOException);
    }
}
